    pub fn dna(&self) -> &Arc<RwLock<DNAsequence>> {
        &self.dna
    }

    fn ensure_full_restriction_site_catalog_current(&mut self) {
        if let Some(engine) = &self.engine
            && let Some(seq_id) = self.seq_id.as_deref()
            && let Ok(mut guard) = engine.write()
            && let Some(dna) = guard.state_mut().sequences.get_mut(seq_id)
        {
            dna.set_max_restriction_enzyme_sites(None);
            dna.update_computed_features();
        }
        if let Ok(mut dna) = self.dna.write() {
            dna.set_max_restriction_enzyme_sites(None);
            dna.update_computed_features();
        }
        self.invalidate_feature_tree_cache();
    }

    pub fn set_pool_context(&mut self, pool_seq_ids: Vec<String>) {
        self.opened_from_pool_context = true;
        self.last_created_seq_ids = pool_seq_ids.clone();
        self.export_pool_inputs_text = pool_seq_ids.join(", ");
        self.show_engine_ops = true;
        self.op_status = "Opened from lineage pool node".to_string();
    }

    fn apply_compact_lane_layout(&mut self) {
        self.show_sequence = false;
        self.show_map = true;
    }

    pub fn enable_compact_lane_layout(&mut self) {
        self.compact_lane_layout = true;
        self.apply_compact_lane_layout();
    }

