    fn mark_dna_layout_dirty(&self) {
        if let Ok(mut display) = self.dna_display.write() {
            display.update_layout_mut().update_all();
        }
    }

    fn suggested_linear_viewport_span_after_topology_switch(
        sequence_length: usize,
    ) -> Option<usize> {
        (sequence_length > LINEAR_TOPOLOGY_SWITCH_MAX_INITIAL_SPAN_BP)
            .then_some(LINEAR_TOPOLOGY_SWITCH_MAX_INITIAL_SPAN_BP.min(sequence_length))
    }

    fn reconcile_linear_viewport_after_dna_replace(
        &self,
        previous_len: usize,
        previous_is_circular: bool,
    ) {
        if self.is_circular() {
            return;
        }
        let new_len = self.dna.read().map(|dna| dna.len()).unwrap_or_default();
        if new_len == 0 {
            return;
        }
        let (start_bp, span_bp) = self
            .dna_display
            .read()
            .map(|display| {
                (
                    display.linear_view_start_bp(),
                    display.linear_view_span_bp(),
                )
            })
            .unwrap_or((0, new_len));

        let was_full_sequence_view = previous_len > 0 && (span_bp == 0 || span_bp >= previous_len);
        if previous_is_circular
            && was_full_sequence_view
            && let Some(initial_span) =
                Self::suggested_linear_viewport_span_after_topology_switch(new_len)
        {
            self.set_linear_viewport(0, initial_span);
            return;
        }

        if was_full_sequence_view && new_len > previous_len {
            self.set_linear_viewport(0, new_len);
            return;
        }
        self.set_linear_viewport(start_bp, span_bp);
    }

    fn log_topology_transition_status(&mut self, stage: &str) {
        if !Self::topology_transition_tracing_enabled() {
            return;
        }
        let (sequence_length, is_circular, feature_count) = self
            .dna
            .read()
            .map(|dna| (dna.len(), dna.is_circular(), dna.features().len()))
            .unwrap_or((0, true, 0));
        let (view_start, view_span) = self
            .dna_display
            .read()
            .map(|display| {
                (
                    display.linear_view_start_bp(),
                    display.linear_view_span_bp(),
                )
            })
            .unwrap_or((0, 0));
        let status = format!(
            "Topology transition [{stage}] | topology={} | len={} bp | features={} | mode={} | primary_map={} | linear_view={}..{} (span {} bp)",
            if is_circular { "circular" } else { "linear" },
            sequence_length,
            feature_count,
            self.dna_presentation_mode.label(),
            self.primary_map_mode.label(),
            view_start.saturating_add(1),
            view_start.saturating_add(view_span),
            view_span,
        );
        self.op_status = status.clone();
        eprintln!("{status}");
    }

    fn topology_transition_tracing_enabled() -> bool {
        env::var(TOPOLOGY_TRANSITION_TRACE_ENV)
            .map(|value| {
                let normalized = value.trim().to_ascii_lowercase();
                !normalized.is_empty()
                    && normalized != "0"
                    && normalized != "false"
                    && normalized != "off"
                    && normalized != "no"
            })
            .unwrap_or(false)
    }

