    fn probe_region_optional_label(value: &Option<String>) -> &str {
        value.as_deref().unwrap_or("not declared")
    }

    fn probe_region_preview_list(values: &[String]) -> String {
        if values.is_empty() {
            return "none".to_string();
        }
        let shown = values.iter().take(8).cloned().collect::<Vec<_>>();
        let suffix = if values.len() > shown.len() {
            format!(" (+{} more)", values.len() - shown.len())
        } else {
            String::new()
        };
        format!("{}{}", shown.join(", "), suffix)
    }

    fn probe_region_mapping_preview(
        mappings: &[ProbeRegionEvidenceTranscriptMapping],
    ) -> String {
        if mappings.is_empty() {
            return "none".to_string();
        }
        let shown = mappings
            .iter()
            .take(4)
            .map(|mapping| {
                let exons = if mapping.exon_ordinals.is_empty() {
                    "none".to_string()
                } else {
                    mapping
                        .exon_ordinals
                        .iter()
                        .map(|ordinal| ordinal.to_string())
                        .collect::<Vec<_>>()
                        .join("/")
                };
                let junctions = if mapping.junction_spans.is_empty() {
                    String::new()
                } else {
                    let spans = mapping
                        .junction_spans
                        .iter()
                        .take(2)
                        .map(|span| {
                            format!(
                                "{}->{}:{}..{}",
                                span.from_exon_ordinal,
                                span.to_exon_ordinal,
                                span.genomic_start_1based,
                                span.genomic_end_1based
                            )
                        })
                        .collect::<Vec<_>>()
                        .join("/");
                    let suffix = if mapping.junction_spans.len() > 2 {
                        format!("+{}", mapping.junction_spans.len() - 2)
                    } else {
                        String::new()
                    };
                    format!(" junctions={spans}{suffix}")
                };
                format!(
                    "{}:{} score={:.2} exons={}{}",
                    mapping.transcript_id,
                    mapping.mapping_kind,
                    mapping.geometry_score,
                    exons,
                    junctions
                )
            })
            .collect::<Vec<_>>();
        let suffix = if mappings.len() > shown.len() {
            format!(" (+{} more)", mappings.len() - shown.len())
        } else {
            String::new()
        };
        format!("{}{}", shown.join("; "), suffix)
    }

    fn optional_probe_region_text(value: &str) -> Option<String> {
        let trimmed = value.trim();
        if trimmed.is_empty() {
            None
        } else {
            Some(trimmed.to_string())
        }
    }

    fn import_apt_probe_region_output_for_current_paths(&mut self) {
        let Some(engine) = self.engine.clone() else {
            self.op_status = "No engine attached".to_string();
            return;
        };
        let summary = self.probe_region_apt_summary_path.trim().to_string();
        let annotation = self.probe_region_apt_annotation_path.trim().to_string();
        let output_dir = self.probe_region_output_dir.trim().to_string();
        if summary.is_empty() {
            self.op_status = "APT summary path is empty".to_string();
            return;
        }
        if annotation.is_empty() {
            self.op_status = "APT annotation path is empty".to_string();
            return;
        }
        if output_dir.is_empty() {
            self.op_status = "Probe-region output directory is empty".to_string();
            return;
        }

        let command = ShellCommand::ArraysImportAptProbeRegionOutput {
            summary,
            annotation,
            output_dir: output_dir.clone(),
            metadata: Self::optional_probe_region_text(&self.probe_region_apt_metadata_path),
            condition_column: Self::optional_probe_region_text(
                &self.probe_region_apt_condition_column,
            ),
            sample_column: Self::optional_probe_region_text(&self.probe_region_apt_sample_column),
            probe_intensity: Self::optional_probe_region_text(
                &self.probe_region_apt_probe_intensity_path,
            ),
            probe_id_column: Self::optional_probe_region_text(
                &self.probe_region_apt_probe_id_column,
            ),
            platform: Self::optional_probe_region_text(&self.probe_region_apt_platform),
            normalization: Self::optional_probe_region_text(&self.probe_region_apt_normalization),
            coordinate_system: Self::optional_probe_region_text(
                &self.probe_region_apt_coordinate_system,
            ),
            genome_build: Self::optional_probe_region_text(&self.probe_region_apt_genome_build),
        };
        let outcome = {
            let mut guard = engine.write().expect("Engine lock poisoned");
            let options = ShellExecutionOptions::from_env();
            execute_shell_command_with_options(&mut guard, &command, &options)
        };
        match outcome {
            Ok(run) => {
                let Some(value) = run.output.get("import").cloned() else {
                    self.cached_probe_region_apt_import = None;
                    self.cached_probe_region_output_inspection = None;
                    self.cached_probe_region_projection = None;
                    self.cached_probe_region_interpretation = None;
                    self.op_status =
                        "APT probe-region import completed without an import payload".to_string();
                    return;
                };
                match serde_json::from_value::<ProbeRegionAptImportReport>(value) {
                    Ok(import) => {
                        let warning_suffix = if import.warnings.is_empty() {
                            String::new()
                        } else {
                            format!(
                                "; warnings: {}",
                                Self::probe_region_preview_list(&import.warnings)
                            )
                        };
                        self.cached_probe_region_output_inspection =
                            Some(import.inspection.clone());
                        self.cached_probe_region_projection = None;
                        self.cached_probe_region_interpretation = None;
                        self.op_status = format!(
                            "APT probe-region output imported to '{}' ({} region rows, {} probe rows, {} missing annotation, {} skipped{})",
                            output_dir,
                            import.written_row_count,
                            import.probe_row_count,
                            import.missing_annotation_count,
                            import.skipped_invalid_count,
                            warning_suffix
                        );
                        self.cached_probe_region_apt_import = Some(import);
                        self.save_engine_ops_state();
                    }
                    Err(err) => {
                        self.cached_probe_region_apt_import = None;
                        self.cached_probe_region_output_inspection = None;
                        self.cached_probe_region_projection = None;
                        self.cached_probe_region_interpretation = None;
                        self.op_status =
                            format!("Could not decode APT import payload: {err}");
                    }
                }
            }
            Err(err) => {
                self.cached_probe_region_apt_import = None;
                self.cached_probe_region_output_inspection = None;
                self.cached_probe_region_projection = None;
                self.cached_probe_region_interpretation = None;
                self.op_status = format!("APT probe-region import failed: {err}");
            }
        }
    }

    fn inspect_probe_region_output_for_current_path(&mut self) {
        let Some(engine) = self.engine.clone() else {
            self.op_status = "No engine attached".to_string();
            return;
        };
        let output_dir = self.probe_region_output_dir.trim().to_string();
        if output_dir.is_empty() {
            self.op_status = "Probe-region output directory is empty".to_string();
            self.cached_probe_region_output_inspection = None;
            self.cached_probe_region_projection = None;
            self.cached_probe_region_interpretation = None;
            return;
        }

        let command = ShellCommand::ArraysInspectProbeRegionOutput {
            output_dir: output_dir.clone(),
        };
        let outcome = {
            let mut guard = engine.write().expect("Engine lock poisoned");
            let options = ShellExecutionOptions::from_env();
            execute_shell_command_with_options(&mut guard, &command, &options)
        };
        match outcome {
            Ok(run) => {
                let Some(value) = run.output.get("inspection").cloned() else {
                    self.cached_probe_region_output_inspection = None;
                    self.cached_probe_region_projection = None;
                    self.cached_probe_region_interpretation = None;
                    self.op_status =
                        "Probe-region inspection completed without an inspection payload"
                            .to_string();
                    return;
                };
                match serde_json::from_value::<ProbeRegionOutputInspection>(value) {
                    Ok(inspection) => {
                        let ready_label = if inspection.projection_ready {
                            "projection-ready"
                        } else {
                            "projection blocked"
                        };
                        self.op_status = format!(
                            "Probe-region output inspected: {} row(s), {} feature(s), {ready_label}",
                            inspection.row_count, inspection.feature_count
                        );
                        self.cached_probe_region_output_inspection = Some(inspection);
                        self.cached_probe_region_interpretation = None;
                        self.save_engine_ops_state();
                    }
                    Err(err) => {
                        self.cached_probe_region_output_inspection = None;
                        self.cached_probe_region_projection = None;
                        self.cached_probe_region_interpretation = None;
                        self.op_status =
                            format!("Could not decode probe-region inspection payload: {err}");
                    }
                }
            }
            Err(err) => {
                self.cached_probe_region_output_inspection = None;
                self.cached_probe_region_projection = None;
                self.cached_probe_region_interpretation = None;
                self.op_status = format!("Probe-region inspection failed: {err}");
            }
        }
    }

    fn export_probe_region_output_svg_for_current_path(&mut self) {
        let Some(engine) = self.engine.clone() else {
            self.op_status = "No engine attached".to_string();
            return;
        };
        let output_dir = self.probe_region_output_dir.trim().to_string();
        let output = self.probe_region_svg_output_path.trim().to_string();
        if output_dir.is_empty() {
            self.op_status = "Probe-region output directory is empty".to_string();
            return;
        }
        if output.is_empty() {
            self.op_status = "Probe-region SVG output path is empty".to_string();
            return;
        }

        let command = ShellCommand::ArraysRenderProbeRegionOutputSvg {
            output_dir: output_dir.clone(),
            output: output.clone(),
        };
        let outcome = {
            let mut guard = engine.write().expect("Engine lock poisoned");
            let options = ShellExecutionOptions::from_env();
            execute_shell_command_with_options(&mut guard, &command, &options)
        };
        match outcome {
            Ok(run) => {
                let row_count = run
                    .output
                    .get("export")
                    .and_then(|value| value.get("row_count"))
                    .and_then(|value| value.as_u64())
                    .unwrap_or(0);
                self.op_status = format!(
                    "Probe-region SVG exported to '{}' ({} row(s))",
                    output, row_count
                );
                self.save_engine_ops_state();
            }
            Err(err) => {
                self.op_status = format!("Probe-region SVG export failed: {err}");
            }
        }
    }

    fn project_probe_region_output_for_current_path(&mut self) {
        let Some(engine) = self.engine.clone() else {
            self.op_status = "No engine attached".to_string();
            return;
        };
        let seq_id = if self.probe_region_projection_seq_id.trim().is_empty() {
            self.seq_id.clone().unwrap_or_default()
        } else {
            self.probe_region_projection_seq_id.trim().to_string()
        };
        let output_dir = self.probe_region_output_dir.trim().to_string();
        if seq_id.is_empty() {
            self.op_status = "Probe-region projection target sequence ID is empty".to_string();
            return;
        }
        if output_dir.is_empty() {
            self.op_status = "Probe-region output directory is empty".to_string();
            return;
        }
        let min_abs_logfc = match Self::parse_optional_f64_text(
            &self.probe_region_projection_min_abs_logfc,
            "probe-region min |log2FC|",
        ) {
            Ok(Some(value)) if value.is_finite() && value >= 0.0 => Some(value),
            Ok(Some(_)) => {
                self.op_status =
                    "Invalid probe-region min |log2FC|: expected a finite value >= 0".to_string();
                return;
            }
            Ok(None) => None,
            Err(message) => {
                self.op_status = message;
                return;
            }
        };
        let max_features = match self.probe_region_projection_max_features.trim() {
            "" => None,
            value => match Self::parse_positive_usize_text(value, "probe-region max features") {
                Ok(parsed) => Some(parsed),
                Err(message) => {
                    self.op_status = message;
                    return;
                }
            },
        };
        let command = ShellCommand::ArraysProjectProbeRegionOutput {
            seq_id: seq_id.clone(),
            output_dir: output_dir.clone(),
            contrasts: Self::parse_ids(&self.probe_region_projection_contrasts),
            level: Self::optional_probe_region_text(&self.probe_region_projection_level),
            min_abs_logfc,
            max_features,
            clear_existing: self.probe_region_projection_clear_existing,
        };
        let started = Instant::now();
        let outcome = {
            let mut guard = engine.write().expect("Engine lock poisoned");
            let options = ShellExecutionOptions::from_env();
            execute_shell_command_with_options(&mut guard, &command, &options)
        };
        match outcome {
            Ok(run) => {
                let Some(value) = run.output.get("result").cloned() else {
                    self.cached_probe_region_projection = None;
                    self.cached_probe_region_interpretation = None;
                    self.op_status =
                        "Probe-region projection completed without an OpResult payload"
                            .to_string();
                    return;
                };
                match serde_json::from_value::<OpResult>(value) {
                    Ok(result) => {
                        let projection = result.microarray_projection.clone();
                        self.probe_region_projection_seq_id = seq_id;
                        self.handle_operation_success(result, started);
                        if let Some(report) = projection {
                            self.op_status = format!(
                                "Probe-region projection imported {} feature(s) into '{}' from '{}' (contrasts={}, parsed={}, skipped={})",
                                report.imported_features,
                                report.seq_id,
                                output_dir,
                                if report.projected_contrasts.is_empty() {
                                    "none".to_string()
                                } else {
                                    report.projected_contrasts.join(",")
                                },
                                report.parsed_rows,
                                report.skipped_rows
                            );
                            self.cached_probe_region_projection = Some(report);
                            self.cached_probe_region_interpretation = None;
                            self.save_engine_ops_state();
                        } else {
                            self.cached_probe_region_projection = None;
                            self.cached_probe_region_interpretation = None;
                            self.op_status =
                                "Probe-region projection completed without a projection report"
                                    .to_string();
                        }
                    }
                    Err(err) => {
                        self.cached_probe_region_projection = None;
                        self.cached_probe_region_interpretation = None;
                        self.op_status =
                            format!("Could not decode probe-region projection payload: {err}");
                    }
                }
            }
            Err(err) => {
                self.cached_probe_region_projection = None;
                self.cached_probe_region_interpretation = None;
                self.op_status = format!("Probe-region projection failed: {err}");
            }
        }
    }

    fn interpret_probe_region_evidence_for_current_sequence(&mut self) {
        let Some(engine) = self.engine.clone() else {
            self.op_status = "No engine attached".to_string();
            return;
        };
        let seq_id = if self.probe_region_projection_seq_id.trim().is_empty() {
            self.seq_id.clone().unwrap_or_default()
        } else {
            self.probe_region_projection_seq_id.trim().to_string()
        };
        if seq_id.is_empty() {
            self.op_status = "Probe-region interpretation target sequence ID is empty".to_string();
            return;
        }
        let min_abs_logfc = match Self::parse_optional_f64_text(
            &self.probe_region_interpretation_min_abs_logfc,
            "probe-region interpretation min |log2FC|",
        ) {
            Ok(Some(value)) if value.is_finite() && value >= 0.0 => Some(value),
            Ok(Some(_)) => {
                self.op_status =
                    "Invalid probe-region interpretation min |log2FC|: expected a finite value >= 0"
                        .to_string();
                return;
            }
            Ok(None) => None,
            Err(message) => {
                self.op_status = message;
                return;
            }
        };
        let output_path =
            Self::optional_probe_region_text(&self.probe_region_interpretation_output_path);
        let command = ShellCommand::ArraysInterpretProbeRegionEvidence {
            seq_id: seq_id.clone(),
            gene_label: Self::optional_probe_region_text(
                &self.probe_region_interpretation_gene_label,
            ),
            level: Self::optional_probe_region_text(&self.probe_region_interpretation_level),
            min_abs_logfc,
            path: output_path.clone(),
        };
        let outcome = {
            let mut guard = engine.write().expect("Engine lock poisoned");
            let options = ShellExecutionOptions::from_env();
            execute_shell_command_with_options(&mut guard, &command, &options)
        };
        match outcome {
            Ok(run) => {
                let Some(value) = run.output.get("result").cloned() else {
                    self.cached_probe_region_interpretation = None;
                    self.op_status =
                        "Probe-region interpretation completed without an OpResult payload"
                            .to_string();
                    return;
                };
                match serde_json::from_value::<OpResult>(value) {
                    Ok(result) => {
                        let report = result.probe_region_evidence_interpretation.clone();
                        if let Some(report) = report {
                            let warnings = if report.warnings.is_empty() {
                                String::new()
                            } else {
                                format!(
                                    "; warnings: {}",
                                    Self::probe_region_preview_list(&report.warnings)
                                )
                            };
                            let output = output_path
                                .as_deref()
                                .map(|path| format!("; wrote {path}"))
                                .unwrap_or_default();
                            self.probe_region_projection_seq_id = seq_id;
                            self.cached_probe_region_interpretation = Some(report.clone());
                            self.op_status = format!(
                                "Probe-region evidence interpreted: {} array feature(s), {} transcript model(s), {} evidence row(s){}{}",
                                report.array_feature_count,
                                report.transcript_count,
                                report.evidence_rows.len(),
                                output,
                                warnings
                            );
                            self.save_engine_ops_state();
                        } else {
                            self.cached_probe_region_interpretation = None;
                            self.op_status =
                                "Probe-region interpretation completed without a report"
                                    .to_string();
                        }
                    }
                    Err(err) => {
                        self.cached_probe_region_interpretation = None;
                        self.op_status =
                            format!("Could not decode probe-region interpretation payload: {err}");
                    }
                }
            }
            Err(err) => {
                self.cached_probe_region_interpretation = None;
                self.op_status = format!("Probe-region interpretation failed: {err}");
            }
        }
    }

    fn render_probe_region_interpretation_summary_panel(
        &self,
        ui: &mut egui::Ui,
        report: &ProbeRegionEvidenceInterpretationReport,
    ) {
        ui.add_space(4.0);
        ui.group(|ui| {
            ui.horizontal_wrapped(|ui| {
                ui.label(egui::RichText::new("Interpretation report").strong());
                ui.small(format!("schema: {}", report.schema));
            });
            ui.small(format!(
                "seq_id: {} | gene: {} | level: {} | min |log2FC|: {}",
                report.seq_id,
                report.gene_label.as_deref().unwrap_or("all"),
                report.level,
                report
                    .min_abs_logfc
                    .map(|value| format!("{value:.3}"))
                    .unwrap_or_else(|| "-".to_string())
            ));
            ui.small(format!(
                "array features: {} | transcript models: {} | evidence rows: {} | transcript rows: {}",
                report.array_feature_count,
                report.transcript_count,
                report.evidence_rows.len(),
                report.transcript_rows.len()
            ));
            if !report.warnings.is_empty() {
                ui.small(
                    egui::RichText::new(format!(
                        "warnings: {}",
                        Self::probe_region_preview_list(&report.warnings)
                    ))
                    .color(egui::Color32::from_rgb(180, 83, 9)),
                );
            }

            if !report.evidence_rows.is_empty() {
                ui.add_space(4.0);
                ui.label(egui::RichText::new("Evidence geometry").strong());
                egui::ScrollArea::vertical()
                    .id_salt(("probe_region_interpretation_evidence", report.seq_id.as_str()))
                    .max_height(150.0)
                    .show(ui, |ui| {
                        egui::Grid::new((
                            "probe_region_interpretation_evidence_grid",
                            report.seq_id.as_str(),
                        ))
                        .striped(true)
                        .num_columns(8)
                        .show(ui, |ui| {
                            ui.strong("evidence");
                            ui.strong("level");
                            ui.strong("logFC");
                            ui.strong("mapping");
                            ui.strong("geometry");
                            ui.strong("transcripts");
                            ui.strong("ambiguity");
                            ui.strong("relationship");
                            ui.end_row();
                            for row in report.evidence_rows.iter().take(24) {
                                ui.small(&row.evidence_id);
                                ui.small(&row.level);
                                ui.small(
                                    row.logfc
                                        .map(|value| format!("{value:.3}"))
                                        .unwrap_or_else(|| "-".to_string()),
                                );
                                ui.small(&row.mapping_status);
                                ui.small(Self::probe_region_mapping_preview(
                                    &row.transcript_mappings,
                                ));
                                ui.small(Self::probe_region_preview_list(
                                    &row.overlapping_transcript_ids,
                                ));
                                ui.small(Self::probe_region_preview_list(&row.ambiguity_tags));
                                ui.small(&row.relationship);
                                ui.end_row();
                            }
                        });
                    });
                if report.evidence_rows.len() > 24 {
                    ui.small(format!(
                        "{} additional evidence row(s) hidden in this preview",
                        report.evidence_rows.len() - 24
                    ));
                }
            }

            if !report.transcript_rows.is_empty() {
                ui.add_space(4.0);
                ui.label(egui::RichText::new("Transcript geometry summary").strong());
                egui::ScrollArea::vertical()
                    .id_salt(("probe_region_interpretation_transcripts", report.seq_id.as_str()))
                    .max_height(150.0)
                    .show(ui, |ui| {
                        egui::Grid::new((
                            "probe_region_interpretation_transcript_grid",
                            report.seq_id.as_str(),
                        ))
                        .striped(true)
                        .num_columns(10)
                        .show(ui, |ui| {
                            ui.strong("transcript");
                            ui.strong("exons");
                            ui.strong("compatible");
                            ui.strong("shared");
                            ui.strong("unique");
                            ui.strong("constraining");
                            ui.strong("score");
                            ui.strong("constraint");
                            ui.strong("review");
                            ui.strong("summary");
                            ui.end_row();
                            for row in report.transcript_rows.iter().take(24) {
                                ui.small(&row.transcript_id);
                                ui.small(row.exon_count.to_string());
                                ui.small(row.compatible_evidence_count.to_string());
                                ui.small(row.shared_evidence_count.to_string());
                                ui.small(row.unique_evidence_count.to_string());
                                ui.small(row.constraining_evidence_count.to_string());
                                ui.small(format!("{:.2}", row.compatible_geometry_score));
                                ui.small(format!("{:.2}", row.constraining_geometry_score));
                                ui.small(&row.review_status);
                                ui.small(&row.relationship_summary);
                                ui.end_row();
                            }
                        });
                    });
                if report.transcript_rows.len() > 24 {
                    ui.small(format!(
                        "{} additional transcript row(s) hidden in this preview",
                        report.transcript_rows.len() - 24
                    ));
                }
            }
        });
    }

