    fn current_linear_viewport(&self) -> (usize, usize, usize) {
        let sequence_length = self.dna.read().expect("DNA lock poisoned").len();
        if sequence_length == 0 {
            return (0, 0, 0);
        }
        let (start_bp, span_bp) = {
            let display = self.dna_display.read().expect("DNA display lock poisoned");
            (
                display.linear_view_start_bp(),
                display.linear_view_span_bp(),
            )
        };
        let span = if span_bp == 0 || span_bp > sequence_length {
            sequence_length
        } else {
            span_bp
        };
        let max_start = sequence_length.saturating_sub(span);
        let start = start_bp.min(max_start);
        (start, span, sequence_length)
    }

    fn current_linear_vertical_offset_px(&self) -> f32 {
        self.dna_display
            .read()
            .map(|display| display.linear_view_vertical_offset_px())
            .unwrap_or(0.0)
    }

    fn linear_base_routing_decision(&self) -> LinearBaseRoutingDecision {
        let (_, span, sequence_length) = self.current_linear_viewport();
        let (compression_enabled, mode_setting) = self
            .dna_display
            .read()
            .map(|display| {
                (
                    display.linear_sequence_helical_letters_enabled(),
                    display.linear_sequence_letter_layout_mode(),
                )
            })
            .unwrap_or((true, LinearSequenceLetterLayoutMode::AutoAdaptive));
        let viewport_width_px =
            if self.last_linear_map_width_px.is_finite() && self.last_linear_map_width_px > 0.0 {
                self.last_linear_map_width_px
            } else {
                1200.0
            };
        decide_linear_base_routing(LinearBaseRoutingInput {
            span_bp: if sequence_length == 0 { 0 } else { span },
            viewport_width_px,
            compression_enabled,
            mode_setting,
            font_scale: 0.85,
            min_font_size_px: 8.0,
            max_font_size_px: 14.0,
        })
    }

    fn linear_map_sequence_bases_visible(&self) -> bool {
        if self.is_circular() {
            return false;
        }
        self.linear_base_routing_decision().bases_visible()
    }

    fn should_auto_hide_sequence_panel(&self) -> bool {
        if !self.show_sequence || !self.show_map {
            return false;
        }
        let auto_hide = self
            .dna_display
            .read()
            .map(|display| display.auto_hide_sequence_panel_when_linear_bases_visible())
            .unwrap_or(false);
        auto_hide && self.linear_map_sequence_bases_visible()
    }

    fn pointer_pos_to_linear_bp(&self, rect: egui::Rect, pointer_pos: egui::Pos2) -> Option<usize> {
        if self.is_circular() || !rect.contains(pointer_pos) {
            return None;
        }
        let (start_bp, span_bp, sequence_length) = self.current_linear_viewport();
        if sequence_length == 0 || span_bp == 0 {
            return None;
        }
        let frac = ((pointer_pos.x - rect.left()) / rect.width().max(1.0)).clamp(0.0, 1.0);
        let bp = start_bp + (frac * span_bp as f32).floor() as usize;
        Some(bp.min(start_bp.saturating_add(span_bp).saturating_sub(1)))
    }

    fn primary_press_origin_inside_rect(ctx: &egui::Context, rect: egui::Rect) -> bool {
        let origin = ctx.input(|input| {
            input
                .pointer
                .primary_down()
                .then(|| input.pointer.press_origin())
                .flatten()
        });
        let Some(origin) = origin else {
            return false;
        };
        rect.contains(origin)
    }

    fn selection_formula_text_for_range(start: usize, end_exclusive: usize) -> String {
        format!("={start} .. {end_exclusive}")
    }

    fn sync_selection_formula_text_to_range(&mut self, start: usize, end_exclusive: usize) {
        self.selection_formula_text = Self::selection_formula_text_for_range(start, end_exclusive);
    }

    fn update_linear_drag_selection(&mut self, anchor_bp: usize, current_bp: usize) {
        let sequence_length = self.dna.read().expect("DNA lock poisoned").len();
        if sequence_length == 0 {
            return;
        }
        let from = anchor_bp
            .min(current_bp)
            .min(sequence_length.saturating_sub(1));
        let to = anchor_bp
            .max(current_bp)
            .saturating_add(1)
            .min(sequence_length);
        self.dna_display
            .write()
            .expect("DNA display lock poisoned")
            .select(Selection::new(from, to, sequence_length));
        self.sync_selection_formula_text_to_range(from, to);
    }

    fn linear_selection_resize_edge_at_pos(
        &self,
        rect: egui::Rect,
        pointer_pos: egui::Pos2,
    ) -> Option<LinearSelectionResizeEdge> {
        if self.is_circular() || !rect.contains(pointer_pos) {
            return None;
        }
        let (selection_start, selection_end_exclusive) = self.current_selection_range_0based()?;
        let (viewport_start, span_bp, sequence_length) = self.current_linear_viewport();
        if span_bp == 0 || sequence_length == 0 {
            return None;
        }
        let viewport_end = viewport_start.saturating_add(span_bp).min(sequence_length);
        if selection_end_exclusive <= viewport_start || selection_start >= viewport_end {
            return None;
        }
        const EDGE_TOLERANCE_PX: f32 = 8.0;
        let edge_x = |bp: usize| {
            let clamped = bp.clamp(viewport_start, viewport_end);
            let frac = (clamped.saturating_sub(viewport_start)) as f32 / span_bp as f32;
            rect.left() + rect.width() * frac.clamp(0.0, 1.0)
        };
        let start_edge_x = (selection_start >= viewport_start).then(|| edge_x(selection_start));
        let end_edge_x =
            (selection_end_exclusive <= viewport_end).then(|| edge_x(selection_end_exclusive));
        let start_distance = start_edge_x.map(|x| (pointer_pos.x - x).abs());
        let end_distance = end_edge_x.map(|x| (pointer_pos.x - x).abs());
        match (start_distance, end_distance) {
            (Some(start), Some(end)) if start <= EDGE_TOLERANCE_PX || end <= EDGE_TOLERANCE_PX => {
                if start <= end {
                    Some(LinearSelectionResizeEdge::Start)
                } else {
                    Some(LinearSelectionResizeEdge::End)
                }
            }
            (Some(start), None) if start <= EDGE_TOLERANCE_PX => {
                Some(LinearSelectionResizeEdge::Start)
            }
            (None, Some(end)) if end <= EDGE_TOLERANCE_PX => Some(LinearSelectionResizeEdge::End),
            _ => None,
        }
    }

    fn apply_linear_selection_resize_drag_bp(
        &mut self,
        drag: LinearSelectionResizeDrag,
        current_bp: usize,
    ) {
        let seq_len = self.dna.read().ok().map(|dna| dna.len()).unwrap_or(0);
        if seq_len == 0 {
            return;
        }
        let (start, end_exclusive) = match drag.edge {
            LinearSelectionResizeEdge::Start => (
                current_bp.min(drag.fixed_end_exclusive.saturating_sub(1)),
                drag.fixed_end_exclusive.min(seq_len),
            ),
            LinearSelectionResizeEdge::End => (
                drag.fixed_start.min(seq_len.saturating_sub(1)),
                current_bp
                    .saturating_add(1)
                    .max(drag.fixed_start.saturating_add(1))
                    .min(seq_len),
            ),
        };
        if end_exclusive <= start {
            return;
        }
        self.dna_display
            .write()
            .expect("DNA display lock poisoned")
            .select(Selection::new(start, end_exclusive, seq_len));
        self.sync_selection_formula_text_to_range(start, end_exclusive);
    }

    fn current_selection_range_0based(&self) -> Option<(usize, usize)> {
        let selection = self
            .dna_display
            .read()
            .ok()
            .and_then(|display| display.selection())?;
        let from = selection.from();
        let to = selection.to();
        if to <= from {
            return None;
        }
        Some((from, to))
    }

    fn set_selection_range_0based(
        &mut self,
        start: usize,
        end_exclusive: usize,
    ) -> Result<(), String> {
        let sequence_length = self
            .dna
            .read()
            .map_err(|_| "DNA lock poisoned while setting selection".to_string())?
            .len();
        if sequence_length == 0 {
            return Err("Cannot select a region on an empty sequence".to_string());
        }
        if start >= sequence_length || end_exclusive > sequence_length || end_exclusive <= start {
            return Err(format!(
                "Invalid selection range {}..{} for sequence length {}",
                start, end_exclusive, sequence_length
            ));
        }
        self.dna_display
            .write()
            .map_err(|_| "DNA display lock poisoned while setting selection".to_string())?
            .select(Selection::new(start, end_exclusive, sequence_length));
        self.map_sequence.request_scroll_to_selection();
        Ok(())
    }

    fn inspect_sequence_span_0based(
        &mut self,
        start: usize,
        end_exclusive: usize,
        context_label: &str,
    ) -> Result<(), String> {
        let sequence_length = self
            .dna
            .read()
            .map_err(|_| "DNA lock poisoned while inspecting span".to_string())?
            .len();
        if sequence_length == 0 {
            return Err("Cannot inspect a span on an empty sequence".to_string());
        }
        let wraps_origin = self.is_circular() && end_exclusive <= start;
        if wraps_origin {
            if start >= sequence_length || end_exclusive >= sequence_length {
                return Err(format!(
                    "Invalid wrapped inspection span {}..{} for circular sequence length {}",
                    start, end_exclusive, sequence_length
                ));
            }
            self.dna_display
                .write()
                .map_err(|_| "DNA display lock poisoned while inspecting span".to_string())?
                .select(Selection::new(start, end_exclusive, sequence_length));
            self.map_sequence.request_scroll_to_selection();
            self.sync_selection_formula_text_to_range(start, end_exclusive);
            self.op_status = format!(
                "Focused {context_label}: wrapped span {}..{} (0-based, end-exclusive on circular sequence)",
                start, end_exclusive
            );
            return Ok(());
        }

        self.set_selection_range_0based(start, end_exclusive)?;
        if !self.is_circular() {
            let (_, span_bp, sequence_length) = self.current_linear_viewport();
            if sequence_length > 0 {
                let span_bp = span_bp.clamp(1, sequence_length);
                let center_bp = start.saturating_add(end_exclusive.saturating_sub(start) / 2);
                let max_start = sequence_length.saturating_sub(span_bp);
                let new_start = center_bp.saturating_sub(span_bp / 2).min(max_start);
                self.set_linear_viewport(new_start, span_bp);
                self.sync_linear_view_input_fields_to_viewport();
            }
        }
        self.op_status = format!(
            "Focused {context_label}: {}..{} (0-based, end-exclusive)",
            start, end_exclusive
        );
        Ok(())
    }

    fn current_visible_linear_span_range_0based(&self) -> Option<(usize, usize)> {
        if self.is_circular() {
            return None;
        }
        let (start, span, sequence_length) = self.current_linear_viewport();
        if sequence_length == 0 || span == 0 {
            return None;
        }
        let end_exclusive = start.saturating_add(span).min(sequence_length);
        if end_exclusive <= start {
            return None;
        }
        Some((start, end_exclusive))
    }

    fn feature_roi_range_0based(&self, feature_id: usize) -> Option<(usize, usize)> {
        let dna = self.dna.read().ok()?;
        let feature = dna.features().get(feature_id)?;
        let mut ranges: Vec<(usize, usize)> = Vec::new();
        collect_location_ranges_usize(&feature.location, &mut ranges);
        if ranges.is_empty() {
            let (from, to) = feature.location.find_bounds().ok()?;
            if from < 0 || to < 0 {
                return None;
            }
            ranges.push((from as usize, to as usize));
        }
        let seq_len = dna.len();
        if seq_len == 0 {
            return None;
        }
        let start = ranges.iter().map(|(start, _)| *start).min()?;
        if start >= seq_len {
            return None;
        }
        let end = ranges
            .iter()
            .map(|(_, end_exclusive)| *end_exclusive)
            .max()?
            .min(seq_len);
        if end <= start {
            return None;
        }
        Some((start, end))
    }

    fn template_length_bp(&self, template: &str) -> Option<usize> {
        if template.trim().is_empty() {
            return None;
        }
        if self.seq_id.as_deref() == Some(template) {
            return self.dna.read().ok().map(|dna| dna.len());
        }
        let engine = self.engine.as_ref()?;
        let guard = engine.read().ok()?;
        guard.state().sequences.get(template).map(|dna| dna.len())
    }

    fn normalize_roi_range_for_template_0based(
        &self,
        template: &str,
        start: usize,
        end_exclusive: usize,
    ) -> Option<(usize, usize)> {
        let seq_len = self.template_length_bp(template)?;
        if seq_len == 0 || start >= seq_len {
            return None;
        }
        let end_exclusive = end_exclusive.min(seq_len);
        if end_exclusive <= start {
            return None;
        }
        Some((start, end_exclusive))
    }

    fn normalize_roi_range_0based(
        &self,
        start: usize,
        end_exclusive: usize,
    ) -> Option<(usize, usize)> {
        let seq_len = self.dna.read().ok()?.len();
        if seq_len == 0 || start >= seq_len {
            return None;
        }
        let end_exclusive = end_exclusive.min(seq_len);
        if end_exclusive <= start {
            return None;
        }
        Some((start, end_exclusive))
    }

    fn pcr_paint_interval_for_role(&self, role: PcrPaintRole) -> Option<(usize, usize)> {
        self.pcr_paint_intervals.get(role)
    }

    fn set_pcr_paint_interval_for_role(
        &mut self,
        role: PcrPaintRole,
        start: usize,
        end_exclusive: usize,
    ) -> Option<(usize, usize)> {
        let normalized = self.normalize_roi_range_0based(start, end_exclusive)?;
        self.pcr_paint_intervals.set(role, Some(normalized));
        Some(normalized)
    }

    fn clear_pcr_paint_interval_for_role(&mut self, role: PcrPaintRole) {
        self.pcr_paint_intervals.set(role, None);
    }

    fn clear_all_pcr_paint_intervals(&mut self) {
        self.pcr_paint_intervals.clear_all();
    }

    fn sync_pcr_post_drag_interval_editor_fields(&mut self, start: usize, end_exclusive: usize) {
        self.pcr_paint_last_drag_start_text = start.to_string();
        self.pcr_paint_last_drag_end_text = end_exclusive.to_string();
    }

    fn apply_pcr_post_drag_interval_editor_fields(&mut self, role: PcrPaintRole) {
        let start = match Self::parse_required_usize_text(
            &self.pcr_paint_last_drag_start_text,
            "painted_interval.start_0based",
        ) {
            Ok(value) => value,
            Err(message) => {
                self.op_status = format!("Invalid painted interval start: {message}");
                return;
            }
        };
        let end_exclusive = match Self::parse_required_usize_text(
            &self.pcr_paint_last_drag_end_text,
            "painted_interval.end_0based_exclusive",
        ) {
            Ok(value) => value,
            Err(message) => {
                self.op_status = format!("Invalid painted interval end: {message}");
                return;
            }
        };
        self.apply_pcr_painted_interval_0based(role, start, end_exclusive, false);
    }

    fn painted_pair_geometry_bp(&self) -> Option<(usize, usize, usize)> {
        let roi = self.pcr_paint_intervals.roi?;
        let upstream = self.pcr_paint_intervals.upstream_window?;
        let downstream = self.pcr_paint_intervals.downstream_window?;
        let roi_len = roi.1.saturating_sub(roi.0);
        let upstream_len = upstream.1.saturating_sub(upstream.0);
        let downstream_len = downstream.1.saturating_sub(downstream.0);
        if roi_len == 0 || upstream_len == 0 || downstream_len == 0 {
            return None;
        }
        Some((roi_len, upstream_len, downstream_len))
    }

    fn queue_painted_roi_from_interval(
        &mut self,
        start: usize,
        end_exclusive: usize,
        source_label: &str,
    ) {
        let template = self.seq_id.clone().unwrap_or_default();
        if template.trim().is_empty() {
            self.op_status = "No active template sequence".to_string();
            return;
        }
        match self.queue_pcr_region(&template, start, end_exclusive, source_label) {
            Ok(true) => {
                self.op_status = format!(
                    "Queued PCR region from {source_label}: {start}..{end_exclusive} (0-based, end-exclusive)"
                );
                self.save_engine_ops_state();
            }
            Ok(false) => {
                self.op_status = format!(
                    "PCR region already queued for template '{}': {}..{}",
                    template, start, end_exclusive
                );
            }
            Err(message) => {
                self.op_status = format!("Could not queue PCR region: {message}");
            }
        }
    }

    fn apply_pcr_painted_interval_0based(
        &mut self,
        role: PcrPaintRole,
        start: usize,
        end_exclusive: usize,
        queue_immediately: bool,
    ) {
        let Some((start, end_exclusive)) =
            self.set_pcr_paint_interval_for_role(role, start, end_exclusive)
        else {
            self.op_status = format!(
                "Could not paint {} interval: invalid range {}..{}",
                role.label(),
                start,
                end_exclusive
            );
            return;
        };
        self.pcr_paint_last_drag_interval = Some((role, start, end_exclusive));
        self.sync_pcr_post_drag_interval_editor_fields(start, end_exclusive);
        if role == PcrPaintRole::Roi && queue_immediately {
            self.queue_painted_roi_from_interval(start, end_exclusive, "painted ROI (shift+drag)");
            self.pcr_paint_drag_interval = None;
            return;
        }
        self.op_status = format!(
            "Painted {} interval: {}..{} (len {} bp)",
            role.label(),
            start,
            end_exclusive,
            end_exclusive.saturating_sub(start)
        );
        self.save_engine_ops_state();
    }

    fn finalize_pcr_map_drag_paint(
        &mut self,
        role: PcrPaintRole,
        anchor_bp: usize,
        current_bp: usize,
        queue_immediately: bool,
    ) {
        let seq_len = self.dna.read().ok().map(|dna| dna.len()).unwrap_or(0);
        if seq_len == 0 {
            return;
        }
        let start = anchor_bp.min(current_bp).min(seq_len.saturating_sub(1));
        let end_exclusive = anchor_bp.max(current_bp).saturating_add(1).min(seq_len);
        if end_exclusive <= start {
            return;
        }
        self.apply_pcr_painted_interval_0based(role, start, end_exclusive, queue_immediately);
    }

    fn handle_linear_map_drag_for_pcr_paint(
        &mut self,
        response: &egui::Response,
        ctx: &egui::Context,
    ) {
        if ctx.input(|input| input.pointer.primary_down())
            && (ctx.dragging_something_else(response.id)
                || !Self::primary_press_origin_inside_rect(ctx, response.rect))
        {
            self.linear_drag_selection_anchor_bp = None;
            self.linear_selection_resize_drag = None;
            self.linear_pan_drag_origin_bp = None;
            self.pcr_paint_drag_interval = None;
            return;
        }

        let option_pan_modifier =
            ctx.input(|i| scroll_input_policy::option_pan_modifier_active(i.modifiers));
        if response.drag_started() {
            if option_pan_modifier {
                self.linear_pan_drag_origin_bp = Some((
                    self.current_linear_viewport().0,
                    if ENABLE_LINEAR_VERTICAL_PAN {
                        self.current_linear_vertical_offset_px()
                    } else {
                        0.0
                    },
                ));
                self.linear_drag_selection_anchor_bp = None;
                self.linear_selection_resize_drag = None;
                self.pcr_paint_drag_interval = None;
            } else if let Some(pos) = response.interact_pointer_pos() {
                if let Some(edge) = self.linear_selection_resize_edge_at_pos(response.rect, pos) {
                    if let Some((start, end_exclusive)) = self.current_selection_range_0based() {
                        self.linear_selection_resize_drag = Some(LinearSelectionResizeDrag {
                            edge,
                            fixed_start: start,
                            fixed_end_exclusive: end_exclusive,
                        });
                        self.linear_drag_selection_anchor_bp = None;
                        self.linear_pan_drag_origin_bp = None;
                        self.pcr_paint_drag_interval = None;
                        self.clear_feature_focus_keep_map_selection();
                    }
                } else if let Some(bp) = self.pointer_pos_to_linear_bp(response.rect, pos) {
                    self.linear_drag_selection_anchor_bp = Some(bp);
                    self.linear_selection_resize_drag = None;
                    self.linear_pan_drag_origin_bp = None;
                    self.update_linear_drag_selection(bp, bp);
                    self.pcr_paint_drag_interval =
                        Some((self.pcr_paint_role, bp, bp.saturating_add(1)));
                    self.clear_feature_focus_keep_map_selection();
                }
            }
        }
        if response.dragged() {
            if let Some((start_bp, start_vertical_offset_px)) = self.linear_pan_drag_origin_bp {
                let (_, span_bp, sequence_length) = self.current_linear_viewport();
                if sequence_length > span_bp {
                    let delta_bp = ((-response.drag_delta().x / response.rect.width().max(1.0))
                        * span_bp as f32)
                        .round() as isize;
                    let max_start = sequence_length.saturating_sub(span_bp) as isize;
                    let new_start = (start_bp as isize + delta_bp).clamp(0, max_start);
                    self.set_linear_viewport(new_start as usize, span_bp);
                }
                if ENABLE_LINEAR_VERTICAL_PAN {
                    self.set_linear_vertical_offset_px(
                        start_vertical_offset_px + response.drag_delta().y,
                    );
                }
                self.pcr_paint_drag_interval = None;
            } else if let Some(resize_drag) = self.linear_selection_resize_drag {
                if let Some(pos) = response.interact_pointer_pos()
                    && let Some(current_bp) = self.pointer_pos_to_linear_bp(response.rect, pos)
                {
                    self.apply_linear_selection_resize_drag_bp(resize_drag, current_bp);
                    self.pcr_paint_drag_interval = None;
                    self.clear_feature_focus_keep_map_selection();
                }
            } else if let (Some(anchor_bp), Some(pos)) = (
                self.linear_drag_selection_anchor_bp,
                response.interact_pointer_pos(),
            ) && let Some(current_bp) = self.pointer_pos_to_linear_bp(response.rect, pos)
            {
                self.update_linear_drag_selection(anchor_bp, current_bp);
                self.pcr_paint_drag_interval = Some((
                    self.pcr_paint_role,
                    anchor_bp.min(current_bp),
                    anchor_bp.max(current_bp).saturating_add(1),
                ));
                self.clear_feature_focus_keep_map_selection();
            }
        }
        if response.drag_stopped() {
            if self.linear_pan_drag_origin_bp.is_none()
                && self.linear_selection_resize_drag.is_none()
                && let Some(anchor_bp) = self.linear_drag_selection_anchor_bp
            {
                let queue_immediately =
                    ctx.input(|i| i.modifiers.shift) && self.pcr_paint_role == PcrPaintRole::Roi;
                if let Some(pos) = response.interact_pointer_pos()
                    && let Some(current_bp) = self.pointer_pos_to_linear_bp(response.rect, pos)
                {
                    self.finalize_pcr_map_drag_paint(
                        self.pcr_paint_role,
                        anchor_bp,
                        current_bp,
                        queue_immediately,
                    );
                } else if let Some((role, start, end_exclusive)) = self.pcr_paint_drag_interval {
                    self.apply_pcr_painted_interval_0based(
                        role,
                        start,
                        end_exclusive,
                        queue_immediately,
                    );
                }
            }
            if self.linear_selection_resize_drag.is_some() {
                self.save_engine_ops_state();
            } else if self.linear_drag_selection_anchor_bp.is_some() {
                self.save_engine_ops_state();
            }
            self.linear_drag_selection_anchor_bp = None;
            self.linear_selection_resize_drag = None;
            self.linear_pan_drag_origin_bp = None;
            self.pcr_paint_drag_interval = None;
        }
        if self.linear_pan_drag_origin_bp.is_some() && !ctx.input(|i| i.pointer.primary_down()) {
            self.linear_pan_drag_origin_bp = None;
        }
        if self.linear_selection_resize_drag.is_some() && !ctx.input(|i| i.pointer.primary_down()) {
            self.linear_selection_resize_drag = None;
        }
    }

    fn draw_pcr_paint_overlays(&self, ui: &mut egui::Ui, response: &egui::Response) {
        if self.is_circular() {
            return;
        }
        let (viewport_start, span_bp, sequence_length) = self.current_linear_viewport();
        if span_bp == 0 || sequence_length == 0 {
            return;
        }
        let viewport_end = viewport_start.saturating_add(span_bp).min(sequence_length);
        let draw_interval = |role: PcrPaintRole, start: usize, end_exclusive: usize, alpha: u8| {
            let clip_start = start.max(viewport_start);
            let clip_end = end_exclusive.min(viewport_end);
            if clip_end <= clip_start {
                return;
            }
            let frac_start = (clip_start.saturating_sub(viewport_start)) as f32 / span_bp as f32;
            let frac_end = (clip_end.saturating_sub(viewport_start)) as f32 / span_bp as f32;
            let x0 = response.rect.left() + response.rect.width() * frac_start.clamp(0.0, 1.0);
            let x1 = response.rect.left() + response.rect.width() * frac_end.clamp(0.0, 1.0);
            let strip = egui::Rect::from_min_max(
                egui::pos2(x0, response.rect.top() + 2.0),
                egui::pos2(x1.max(x0 + 1.0), response.rect.top() + 12.0),
            );
            ui.painter().rect_filled(
                strip,
                2.0,
                role.color()
                    .linear_multiply((alpha as f32 / 255.0).clamp(0.0, 1.0)),
            );
        };
        for role in [
            PcrPaintRole::Roi,
            PcrPaintRole::UpstreamPrimerWindow,
            PcrPaintRole::DownstreamPrimerWindow,
        ] {
            if let Some((start, end_exclusive)) = self.pcr_paint_interval_for_role(role) {
                draw_interval(role, start, end_exclusive, 120);
            }
        }
        if let Some((role, start, end_exclusive)) = self.pcr_paint_drag_interval {
            draw_interval(role, start, end_exclusive, 210);
            let text = format!(
                "{} {}..{} ({} bp)",
                role.short_label(),
                start,
                end_exclusive,
                end_exclusive.saturating_sub(start)
            );
            ui.painter().text(
                response.rect.left_top() + egui::vec2(8.0, 16.0),
                egui::Align2::LEFT_TOP,
                text,
                egui::TextStyle::Small.resolve(ui.style()),
                role.color(),
            );
        }
    }

    fn render_pcr_paint_role_controls(&mut self, ui: &mut egui::Ui, include_clear_all: bool) {
        ui.label("PCR paint role:");
        for role in [
            PcrPaintRole::Roi,
            PcrPaintRole::UpstreamPrimerWindow,
            PcrPaintRole::DownstreamPrimerWindow,
        ] {
            let label = egui::RichText::new(role.short_label()).color(role.color());
            let response = ui.selectable_value(&mut self.pcr_paint_role, role, label);
            response.on_hover_text(role.hover_text());
        }
        if ui
            .small_button("Clear role")
            .on_hover_text("Clear currently selected paint role interval")
            .clicked()
        {
            self.clear_pcr_paint_interval_for_role(self.pcr_paint_role);
            self.op_status = format!("Cleared {}", self.pcr_paint_role.label());
            self.save_engine_ops_state();
        }
        if include_clear_all
            && ui
                .small_button("Clear all")
                .on_hover_text("Clear ROI/upstream/downstream painted intervals")
                .clicked()
        {
            self.clear_all_pcr_paint_intervals();
            self.op_status = "Cleared all PCR paint intervals".to_string();
            self.save_engine_ops_state();
        }
    }

    fn render_pcr_paint_interval_summary(&self, ui: &mut egui::Ui) {
        let draw_row = |ui: &mut egui::Ui, role: PcrPaintRole, span: Option<(usize, usize)>| {
            ui.label(egui::RichText::new(role.label()).color(role.color()));
            match span {
                Some((start, end_exclusive)) => {
                    ui.monospace(format!(
                        "{}..{} ({} bp)",
                        start,
                        end_exclusive,
                        end_exclusive.saturating_sub(start)
                    ));
                }
                None => {
                    ui.label("-");
                }
            }
            ui.end_row();
        };
        egui::Grid::new("pcr_paint_interval_summary")
            .num_columns(2)
            .striped(true)
            .show(ui, |ui| {
                draw_row(ui, PcrPaintRole::Roi, self.pcr_paint_intervals.roi);
                draw_row(
                    ui,
                    PcrPaintRole::UpstreamPrimerWindow,
                    self.pcr_paint_intervals.upstream_window,
                );
                draw_row(
                    ui,
                    PcrPaintRole::DownstreamPrimerWindow,
                    self.pcr_paint_intervals.downstream_window,
                );
            });
    }

    fn render_pcr_post_drag_actions(&mut self, ui: &mut egui::Ui) {
        let Some((role, start, end_exclusive)) = self.pcr_paint_last_drag_interval else {
            return;
        };
        if self.pcr_paint_last_drag_start_text.trim().is_empty()
            || self.pcr_paint_last_drag_end_text.trim().is_empty()
        {
            self.sync_pcr_post_drag_interval_editor_fields(start, end_exclusive);
        }
        ui.group(|ui| {
            ui.horizontal_wrapped(|ui| {
                ui.label(
                    egui::RichText::new(format!(
                        "Painted {}: {}..{} ({} bp)",
                        role.label(),
                        start,
                        end_exclusive,
                        end_exclusive.saturating_sub(start)
                    ))
                    .color(role.color()),
                );
                if ui
                    .small_button("Set PCR ROI")
                    .on_hover_text("Copy this painted interval into pair-PCR ROI fields")
                    .clicked()
                {
                    self.seed_primer_design_roi_0based(
                        start,
                        end_exclusive,
                        &format!("painted {} interval", role.label()),
                    );
                }
                if ui
                    .small_button("Add ROI to Queue")
                    .on_hover_text("Queue this painted interval as one PCR batch region")
                    .clicked()
                {
                    self.queue_painted_roi_from_interval(start, end_exclusive, role.source_label());
                }
                if ui
                    .small_button("Open PCR Designer")
                    .on_hover_text("Open dedicated PCR specialist window for this sequence context")
                    .clicked()
                {
                    self.request_open_pcr_design_for_current_sequence();
                    self.op_status = "Requested dedicated PCR Designer window".to_string();
                }
                if ui.small_button("Dismiss").clicked() {
                    self.pcr_paint_last_drag_interval = None;
                    self.pcr_paint_last_drag_start_text.clear();
                    self.pcr_paint_last_drag_end_text.clear();
                }
            });
            ui.horizontal(|ui| {
                ui.label("Edit interval");
                let start_response = ui
                    .add(
                        egui::TextEdit::singleline(&mut self.pcr_paint_last_drag_start_text)
                            .desired_width(90.0),
                    )
                    .on_hover_text("0-based start coordinate");
                ui.monospace("..");
                let end_response = ui
                    .add(
                        egui::TextEdit::singleline(&mut self.pcr_paint_last_drag_end_text)
                            .desired_width(90.0),
                    )
                    .on_hover_text("0-based end coordinate (exclusive)");
                let enter_pressed = ui.input(|i| i.key_pressed(egui::Key::Enter));
                if ui
                    .small_button("Apply")
                    .on_hover_text("Update this painted interval from the typed coordinates")
                    .clicked()
                    || (enter_pressed && (start_response.lost_focus() || end_response.lost_focus()))
                {
                    self.apply_pcr_post_drag_interval_editor_fields(role);
                }
            });
        });
    }

    fn set_primer_design_roi_fields_0based(&mut self, start: usize, end_exclusive: usize) {
        self.primer_design_ui.roi_start_0based = start.to_string();
        self.primer_design_ui.roi_end_0based = end_exclusive.to_string();
        self.qpcr_design_ui.roi_start_0based = start.to_string();
        self.qpcr_design_ui.roi_end_0based = end_exclusive.to_string();
    }

    fn seed_simple_pcr_roi_0based(
        &mut self,
        start: usize,
        end_exclusive: usize,
        source: &str,
    ) -> Result<(usize, usize), String> {
        let Some((start, end_exclusive)) = self.normalize_roi_range_0based(start, end_exclusive)
        else {
            return Err(format!(
                "Could not seed simple PCR from {source}: invalid 0-based range {start}..{end_exclusive}"
            ));
        };
        let core_len_bp = end_exclusive.saturating_sub(start);
        self.set_primer_design_roi_fields_0based(start, end_exclusive);
        self.primer_design_ui.pair_constraints.require_roi_flanking = true;
        self.primer_design_ui.min_amplicon_bp = core_len_bp.to_string();
        if let Ok(max_amplicon_bp) = Self::parse_positive_usize_text(
            &self.primer_design_ui.max_amplicon_bp,
            "max_amplicon_bp",
        ) && max_amplicon_bp < core_len_bp
        {
            self.primer_design_ui.max_amplicon_bp = core_len_bp.to_string();
        }
        self.save_engine_ops_state();
        Ok((start, end_exclusive))
    }

    fn apply_simple_pcr_flank_windows_from_roi(&mut self) -> Result<(), String> {
        let (roi_start_0based, roi_end_0based_exclusive) = self.resolve_roi_range_inputs_0based(
            &self.primer_design_ui.roi_start_0based,
            &self.primer_design_ui.roi_end_0based,
            "primer_design",
        )?;
        let max_distance_bp = Self::parse_positive_usize_text(
            &self.simple_pcr_max_primer_distance_bp,
            "simple_pcr_max_primer_distance_bp",
        )?;
        let template_len = self.dna.read().expect("DNA lock poisoned").len();
        let forward_start_0based = roi_start_0based.saturating_sub(max_distance_bp);
        let forward_end_0based_exclusive = roi_start_0based;
        let reverse_start_0based = roi_end_0based_exclusive;
        let reverse_end_0based_exclusive = roi_end_0based_exclusive
            .saturating_add(max_distance_bp)
            .min(template_len);
        self.primer_design_ui.forward.location_0based.clear();
        self.primer_design_ui.forward.start_0based = forward_start_0based.to_string();
        self.primer_design_ui.forward.end_0based = forward_end_0based_exclusive.to_string();
        self.primer_design_ui.reverse.location_0based.clear();
        self.primer_design_ui.reverse.start_0based = reverse_start_0based.to_string();
        self.primer_design_ui.reverse.end_0based = reverse_end_0based_exclusive.to_string();
        self.primer_design_ui.pair_constraints.require_roi_flanking = true;
        self.save_engine_ops_state();
        self.op_status = format!(
            "Applied simple PCR flank windows around core ROI: forward {}..{}, reverse {}..{}, max primer distance {} bp",
            forward_start_0based,
            forward_end_0based_exclusive,
            reverse_start_0based,
            reverse_end_0based_exclusive,
            max_distance_bp
        );
        Ok(())
    }

    fn open_simple_pcr_designer_from_current_selection(&mut self) {
        let Some((start, end_exclusive)) = self.current_selection_range_0based() else {
            self.op_status =
                "No active selection. Drag-select a core region before starting simple PCR."
                    .to_string();
            return;
        };
        match self.seed_simple_pcr_roi_0based(start, end_exclusive, "current sequence selection") {
            Ok((start, end_exclusive)) => {
                if let Err(message) = self.apply_simple_pcr_flank_windows_from_roi() {
                    self.op_status = message;
                    return;
                }
                self.request_open_pcr_design_for_current_sequence();
                self.op_status = format!(
                    "Seeded simple PCR from current selection: core {}..{}; max primer distance {} bp; open PCR Designer and set max amplicon as needed",
                    start,
                    end_exclusive,
                    self.simple_pcr_max_primer_distance_bp.trim()
                );
            }
            Err(message) => {
                self.op_status = message;
            }
        }
    }

    fn set_primer_design_roi_from_current_selection(&mut self, source: &str) -> Result<(), String> {
        let Some((start, end_exclusive)) = self.current_selection_range_0based() else {
            return Err(
                "No active map/sequence selection. Drag-select a region first.".to_string(),
            );
        };
        self.set_primer_design_roi_fields_0based(start, end_exclusive);
        self.op_status = format!("Set pair-PCR ROI fields from {source}: {start}..{end_exclusive}");
        self.save_engine_ops_state();
        Ok(())
    }

    fn request_open_pcr_design_for_current_sequence(&self) {
        if let Some(seq_id) = self.seq_id.as_deref() {
            request_open_pcr_design_for_sequence_from_native_menu(seq_id);
        } else {
            request_open_pcr_design_from_native_menu();
        }
    }

    fn active_pcr_roi_source_0based(&self) -> Option<(usize, usize, &'static str)> {
        if let Some((start, end_exclusive)) = self.current_selection_range_0based() {
            Some((start, end_exclusive, "current sequence selection"))
        } else {
            self.pcr_paint_intervals
                .roi
                .map(|(start, end_exclusive)| (start, end_exclusive, "painted ROI interval"))
        }
    }

    fn seed_primer_design_roi_from_active_region(&mut self) -> Result<(), String> {
        let Some((start, end_exclusive, source)) = self.active_pcr_roi_source_0based() else {
            return Err(
                "No active map/sequence selection or painted ROI interval. Drag-select a region or paint an ROI first."
                    .to_string(),
            );
        };
        self.seed_primer_design_roi_0based(start, end_exclusive, source);
        Ok(())
    }

    fn seed_primer_design_roi_0based(&mut self, start: usize, end_exclusive: usize, source: &str) {
        let Some((start, end_exclusive)) = self.normalize_roi_range_0based(start, end_exclusive)
        else {
            self.op_status = format!(
                "Could not seed primer ROI from {source}: invalid 0-based range {start}..{end_exclusive}"
            );
            return;
        };
        self.set_primer_design_roi_fields_0based(start, end_exclusive);
        self.request_open_pcr_design_for_current_sequence();
        self.op_status = format!(
            "Seeded primer/qPCR ROI from {source}: {start}..{end_exclusive} (0-based, end-exclusive); open PCR Designer for pair-PCR review"
        );
        self.save_engine_ops_state();
    }

    fn qpcr_specificity_evidence_label(
        evidence: QpcrTranscriptSpecificityEvidence,
    ) -> &'static str {
        match evidence {
            QpcrTranscriptSpecificityEvidence::JunctionOnly => "Junction only",
            QpcrTranscriptSpecificityEvidence::UniqueExonOrChain => "Unique exon / exon chain only",
            QpcrTranscriptSpecificityEvidence::EitherPreferJunction => "Either (prefer junction)",
        }
    }

    fn qpcr_transcript_context_is_compatible(&self, template: &str) -> bool {
        let targeting = &self.qpcr_design_ui.transcript_targeting;
        targeting.source_feature_id.is_some()
            && !targeting.source_seq_id.trim().is_empty()
            && targeting.source_seq_id == template
    }

    fn qpcr_transcript_context_summary(&self, template: &str) -> Option<String> {
        let targeting = &self.qpcr_design_ui.transcript_targeting;
        if !self.qpcr_transcript_context_is_compatible(template) {
            return None;
        }
        let mut chunks = vec![
            format!("group={}", targeting.group_label),
            format!("transcripts={}", targeting.transcript_count),
            format!("strand={}", targeting.strand),
            "scope=target-group strand".to_string(),
        ];
        if targeting.assay_intent == QpcrTranscriptIntentUiMode::SpecificTranscript
            && !targeting.selected_transcript_id.trim().is_empty()
        {
            let label = targeting.selected_transcript_label.trim();
            let transcript = targeting.selected_transcript_id.trim();
            if !label.is_empty() && !label.eq_ignore_ascii_case(transcript) {
                chunks.push(format!("selected={} ({})", transcript, label));
            } else {
                chunks.push(format!("selected={transcript}"));
            }
        }
        Some(chunks.join(" | "))
    }

    fn apply_qpcr_transcript_targeting_context_from_view(
        &mut self,
        view: &SplicingExpertView,
        assay_intent: QpcrTranscriptIntentUiMode,
    ) -> Result<(), String> {
        let selected_transcript_feature_id = self.splicing_selected_transcript_feature_id(view);
        let selected_transcript = selected_transcript_feature_id.and_then(|feature_id| {
            view.transcripts
                .iter()
                .find(|row| row.transcript_feature_id == feature_id)
        });
        if assay_intent == QpcrTranscriptIntentUiMode::SpecificTranscript
            && selected_transcript.is_none()
        {
            return Err(
                "Specific-transcript qPCR requires a selected transcript in Splicing Expert"
                    .to_string(),
            );
        }
        let targeting = &mut self.qpcr_design_ui.transcript_targeting;
        targeting.assay_intent = assay_intent;
        targeting.source_seq_id = view.seq_id.clone();
        targeting.source_feature_id = Some(view.target_feature_id);
        targeting.group_label = view.group_label.clone();
        targeting.transcript_count = view.transcript_count.max(view.transcripts.len());
        targeting.strand = view.strand.clone();
        targeting.selected_transcript_feature_id = selected_transcript_feature_id;
        targeting.selected_transcript_id = selected_transcript
            .map(|row| row.transcript_id.clone())
            .unwrap_or_default();
        targeting.selected_transcript_label = selected_transcript
            .map(|row| row.label.clone())
            .unwrap_or_default();
        Ok(())
    }

    fn seed_qpcr_from_splicing_view(
        &mut self,
        view: &SplicingExpertView,
        assay_intent: QpcrTranscriptIntentUiMode,
    ) -> Result<(), String> {
        let (start, end_exclusive) = Self::splicing_group_roi_range_0based(view)
            .ok_or_else(|| "Could not derive a valid ROI from splicing group bounds".to_string())?;
        let (start, end_exclusive) = self
            .normalize_roi_range_0based(start, end_exclusive)
            .ok_or_else(|| {
                format!(
                    "Could not seed qPCR ROI from splicing group '{}': invalid 0-based range {}..{}",
                    view.group_label, start, end_exclusive
                )
            })?;
        self.set_primer_design_roi_fields_0based(start, end_exclusive);
        self.pcr_designer_mode = PcrDesignerMode::QpcrAssays;
        self.apply_qpcr_transcript_targeting_context_from_view(view, assay_intent)?;
        self.request_open_pcr_design_for_current_sequence();
        let mode_label = match assay_intent {
            QpcrTranscriptIntentUiMode::Genomic => "genomic qPCR",
            QpcrTranscriptIntentUiMode::SharedAcrossTranscripts => "shared-transcript qPCR",
            QpcrTranscriptIntentUiMode::SpecificTranscript => "transcript-specific qPCR",
        };
        self.op_status = format!(
            "Seeded {mode_label} from splicing group '{}' on {}: {}..{} (0-based, end-exclusive); open PCR Designer for qPCR review",
            view.group_label, view.seq_id, start, end_exclusive
        );
        self.save_engine_ops_state();
        Ok(())
    }

    fn focus_or_open_qpcr_splicing_expert(&mut self, ctx: &egui::Context, template: &str) {
        if let Some(view) = self.relevant_qpcr_splicing_view_for_template(template) {
            self.open_splicing_expert_window_for_view(&view);
            self.focus_splicing_expert_window_view(ctx, &view);
            self.op_status = format!(
                "Focused Splicing Expert for transcript-aware qPCR on '{}'",
                template
            );
            return;
        }
        if let Some(feature_id) = self
            .get_selected_feature_id()
            .filter(|feature_id| self.feature_supports_splicing_expert(*feature_id))
            && let Ok(view) = self.splicing_expert_view_for_feature(feature_id)
        {
            self.open_splicing_expert_window_for_view(&view);
            self.focus_splicing_expert_window_view(ctx, &view);
            self.op_status = format!(
                "Opened Splicing Expert from selected feature n-{} for transcript-aware qPCR",
                feature_id
            );
            return;
        }
        self.op_status = "Transcript-aware qPCR must be seeded from a splicing overview. Select a transcript-linked feature and open Splicing Expert first.".to_string();
    }

    fn validate_qpcr_transcript_targeting_ui(&self, template: &str) -> Result<(), String> {
        let targeting = &self.qpcr_design_ui.transcript_targeting;
        match targeting.assay_intent {
            QpcrTranscriptIntentUiMode::Genomic => Ok(()),
            QpcrTranscriptIntentUiMode::SharedAcrossTranscripts => {
                if self.qpcr_transcript_context_is_compatible(template) {
                    Ok(())
                } else {
                    Err(
                        "Transcript-aware qPCR must be seeded from a splicing overview on this sequence."
                            .to_string(),
                    )
                }
            }
            QpcrTranscriptIntentUiMode::SpecificTranscript => {
                if !self.qpcr_transcript_context_is_compatible(template) {
                    return Err(
                        "Transcript-aware qPCR must be seeded from a splicing overview on this sequence."
                            .to_string(),
                    );
                }
                if targeting.selected_transcript_id.trim().is_empty() {
                    return Err(
                        "Select a transcript in Splicing Expert before designing transcript-specific qPCR."
                            .to_string(),
                    );
                }
                Ok(())
            }
        }
    }

    fn build_qpcr_transcript_targeting_from_ui(
        &self,
        template: &str,
    ) -> Result<Option<QpcrTranscriptTargeting>, String> {
        self.validate_qpcr_transcript_targeting_ui(template)?;
        let targeting = &self.qpcr_design_ui.transcript_targeting;
        let Some(source_feature_id) = targeting.source_feature_id else {
            return Ok(None);
        };
        match targeting.assay_intent {
            QpcrTranscriptIntentUiMode::Genomic => Ok(None),
            QpcrTranscriptIntentUiMode::SharedAcrossTranscripts => {
                Ok(Some(QpcrTranscriptTargeting {
                    source_feature_id,
                    mode: QpcrTranscriptTargetingMode::SharedGene,
                    transcript_id: None,
                    specificity_evidence: None,
                }))
            }
            QpcrTranscriptIntentUiMode::SpecificTranscript => Ok(Some(QpcrTranscriptTargeting {
                source_feature_id,
                mode: QpcrTranscriptTargetingMode::DistinguishTranscript,
                transcript_id: Some(targeting.selected_transcript_id.trim().to_string()),
                specificity_evidence: Some(targeting.specificity_evidence),
            })),
        }
    }

    fn selected_feature_ids_for_pcr_roi_actions(&self) -> Vec<usize> {
        let mut feature_ids: Vec<usize> = self.multi_selected_feature_ids.iter().copied().collect();
        if feature_ids.is_empty() {
            if let Some(feature_id) = self.get_selected_feature_id() {
                feature_ids.push(feature_id);
            }
        } else if let Some(feature_id) = self.get_selected_feature_id() {
            feature_ids.push(feature_id);
        }
        feature_ids.sort_unstable();
        feature_ids.dedup();
        feature_ids
    }

    fn queue_pcr_region(
        &mut self,
        template: &str,
        start: usize,
        end_exclusive: usize,
        source_label: &str,
    ) -> Result<bool, String> {
        let normalized = self
            .normalize_roi_range_for_template_0based(template, start, end_exclusive)
            .ok_or_else(|| {
                format!(
                    "Invalid PCR ROI {start}..{end_exclusive} (0-based, end-exclusive) for template '{template}'"
                )
            })?;
        if self.pcr_queued_regions_ui.iter().any(|row| {
            row.template == template
                && row.start_0based == normalized.0
                && row.end_0based_exclusive == normalized.1
        }) {
            return Ok(false);
        }
        self.pcr_queued_regions_ui.push(PcrQueuedRegionUiState {
            template: template.to_string(),
            source_label: source_label.to_string(),
            start_0based: normalized.0,
            end_0based_exclusive: normalized.1,
        });
        Ok(true)
    }

    fn queue_current_selection_for_pcr(&mut self) {
        let template = self.seq_id.clone().unwrap_or_default();
        if template.trim().is_empty() {
            self.op_status = "No active template sequence".to_string();
            return;
        }
        let Some((start, end_exclusive)) = self.current_selection_range_0based() else {
            self.op_status = "No non-empty linear selection available to queue for PCR".to_string();
            return;
        };
        match self.queue_pcr_region(
            &template,
            start,
            end_exclusive,
            "current sequence selection",
        ) {
            Ok(true) => {
                self.op_status = format!(
                    "Queued PCR region from current selection: {start}..{end_exclusive} (0-based, end-exclusive)"
                );
                self.save_engine_ops_state();
            }
            Ok(false) => {
                self.op_status = format!(
                    "PCR region already queued for template '{}': {}..{}",
                    template, start, end_exclusive
                );
            }
            Err(message) => {
                self.op_status = format!("Could not queue PCR region: {message}");
            }
        }
    }

    fn run_restriction_site_scan_for_active_sequence(
        &mut self,
        span: Option<(usize, usize)>,
        source_label: &str,
    ) {
        let template = self.seq_id.clone().unwrap_or_default();
        if template.trim().is_empty() {
            self.op_status = "No active template sequence".to_string();
            return;
        }
        let target = SequenceScanTarget::SeqId {
            seq_id: template.clone(),
            span_start_0based: span.map(|(start, _)| start),
            span_end_0based_exclusive: span.map(|(_, end_exclusive)| end_exclusive),
        };
        let Some(result) =
            self.apply_operation_with_feedback_and_result(Operation::FindRestrictionSites {
                target,
                enzymes: vec![],
                max_sites_per_enzyme: None,
                include_cut_geometry: true,
                path: None,
            })
        else {
            return;
        };
        let Some(report) = result.restriction_site_scan else {
            return;
        };
        self.cached_restriction_site_scan = Some(report.clone());
        let hit_preview = report
            .rows
            .iter()
            .take(4)
            .map(|row| {
                format!(
                    "{}@{}",
                    row.enzyme_name, row.source_recognition_start_0based
                )
            })
            .collect::<Vec<_>>();
        self.op_status = if hit_preview.is_empty() {
            format!(
                "Restriction-site scan for {source_label} on '{}' found no sites across {} enzyme(s)",
                template,
                report.enzymes_scanned.len()
            )
        } else {
            format!(
                "Restriction-site scan for {source_label} on '{}' found {} site(s) across {} enzyme(s): {}",
                template,
                report.matched_site_count,
                report.enzymes_scanned.len(),
                hit_preview.join(", ")
            )
        };
    }

    fn scan_current_selection_for_restriction_sites(&mut self) {
        let Some((start, end_exclusive)) = self.current_selection_range_0based() else {
            self.op_status =
                "No non-empty linear selection available for restriction-site scan".to_string();
            return;
        };
        self.run_restriction_site_scan_for_active_sequence(
            Some((start, end_exclusive)),
            "current selection",
        );
    }

    fn scan_visible_span_for_restriction_sites(&mut self) {
        let Some((start, end_exclusive)) = self.current_visible_linear_span_range_0based() else {
            self.op_status =
                "Visible linear span is unavailable for restriction-site scan".to_string();
            return;
        };
        self.run_restriction_site_scan_for_active_sequence(
            Some((start, end_exclusive)),
            "visible span",
        );
    }

    fn scan_whole_sequence_for_restriction_sites(&mut self) {
        self.run_restriction_site_scan_for_active_sequence(None, "whole sequence");
    }

    fn run_tfbs_hit_scan_for_active_sequence(
        &mut self,
        span: Option<(usize, usize)>,
        source_label: &str,
    ) {
        let template = self.seq_id.clone().unwrap_or_default();
        if template.trim().is_empty() {
            self.op_status = "No active template sequence".to_string();
            return;
        }
        let (motifs, min_llr_bits, min_llr_quantile, per_tf_thresholds) =
            match self.collect_tfbs_scan_settings() {
                Ok(settings) => settings,
                Err(message) => {
                    self.op_status = message;
                    return;
                }
            };
        let target = SequenceScanTarget::SeqId {
            seq_id: template.clone(),
            span_start_0based: span.map(|(start, _)| start),
            span_end_0based_exclusive: span.map(|(_, end_exclusive)| end_exclusive),
        };
        let Some(result) = self.apply_operation_with_feedback_and_result(Operation::ScanTfbsHits {
            target,
            motifs,
            min_llr_bits,
            min_llr_quantile,
            per_tf_thresholds,
            max_hits: Some(GUI_TFBS_SCAN_MAX_HITS),
            path: None,
        }) else {
            return;
        };
        let Some(report) = result.tfbs_hit_scan else {
            return;
        };
        self.cached_tfbs_hit_scan = Some(report.clone());
        let hit_preview = report
            .rows
            .iter()
            .take(4)
            .map(|row| {
                format!(
                    "{}@{}{}",
                    row.tf_name.as_deref().unwrap_or(&row.tf_id),
                    row.source_match_start_0based,
                    if row.forward_strand { "+" } else { "-" }
                )
            })
            .collect::<Vec<_>>();
        let truncation_note = if report.truncated_at_max_hits {
            format!(
                " (truncated at {} hits for quick GUI inspection)",
                report.max_hits.unwrap_or_default()
            )
        } else {
            String::new()
        };
        self.op_status = if hit_preview.is_empty() {
            format!(
                "TFBS scan for {source_label} on '{}' found no hits across {} motif(s){}",
                template,
                report.motifs_scanned.len(),
                truncation_note
            )
        } else {
            format!(
                "TFBS scan for {source_label} on '{}' matched {} hit(s) across {} motif(s): {}{}",
                template,
                report.matched_hit_count,
                report.motifs_scanned.len(),
                hit_preview.join(", "),
                truncation_note
            )
        };
    }

    fn scan_current_selection_for_tfbs_hits(&mut self) {
        let Some((start, end_exclusive)) = self.current_selection_range_0based() else {
            self.op_status = "No non-empty linear selection available for TFBS scan".to_string();
            return;
        };
        self.run_tfbs_hit_scan_for_active_sequence(
            Some((start, end_exclusive)),
            "current selection",
        );
    }

    fn scan_visible_span_for_tfbs_hits(&mut self) {
        let Some((start, end_exclusive)) = self.current_visible_linear_span_range_0based() else {
            self.op_status = "Visible linear span is unavailable for TFBS scan".to_string();
            return;
        };
        self.run_tfbs_hit_scan_for_active_sequence(Some((start, end_exclusive)), "visible span");
    }

    fn scan_whole_sequence_for_tfbs_hits(&mut self) {
        self.run_tfbs_hit_scan_for_active_sequence(None, "whole sequence");
    }

