    fn save_engine_ops_state(&self) {
        let Some(engine) = &self.engine else {
            return;
        };
        let key = self.engine_ops_state_key();
        let value = match serde_json::to_value(self.current_engine_ops_state()) {
            Ok(v) => v,
            Err(_) => return,
        };
        let mut guard = engine.write().expect("Engine lock poisoned");
        if guard.state().metadata.get(&key) == Some(&value) {
            return;
        }
        guard.state_mut().metadata.insert(key, value);
    }

    fn load_engine_ops_state(&mut self) {
        let Some(engine) = &self.engine else {
            return;
        };
        let key = self.engine_ops_state_key();
        let value = engine
            .read()
            .expect("Engine lock poisoned")
            .state()
            .metadata
            .get(&key)
            .cloned();
        if let Some(value) = value
            && let Ok(state) = serde_json::from_value::<EngineOpsUiState>(value)
        {
            self.apply_engine_ops_state(state);
        }
    }

    fn render_error_popup(&mut self, ctx: &egui::Context) {
        let Some(message) = self.op_error_popup.clone() else {
            return;
        };
        let mut open = true;
        let spec = crate::egui_compat::ModalWindowSpec::new(
            "Operation Failed",
            egui::Id::new(("dna_operation_failed", self.panel_scope_key())),
        );
        crate::egui_compat::show_modal_window(ctx, &spec, &mut open, |ui| {
            ui.label(message);
            if ui
                .button("Close")
                .on_hover_text("Dismiss this error popup")
                .clicked()
            {
                self.op_error_popup = None;
            }
        });
        if !open {
            self.op_error_popup = None;
        }
    }

    fn render_anchor_prepared_choice_popup(&mut self, ctx: &egui::Context) {
        let mut open = true;
        let mut apply_clicked = false;
        let mut cancel_clicked = false;
        let popup_scope = self.panel_scope_key();
        {
            let Some(dialog) = self.anchor_prepared_choice_dialog.as_mut() else {
                return;
            };
            let spec = crate::egui_compat::ModalWindowSpec::new(
                "Select Prepared Genome",
                egui::Id::new(("dna_anchor_prepared_choice", popup_scope)),
            )
            .default_size(egui::vec2(460.0, 140.0));
            crate::egui_compat::show_modal_window(ctx, &spec, &mut open, |ui| {
                ui.label(format!(
                    "Requested genome '{}' has multiple compatible prepared references.",
                    dialog.requested_genome_id
                ));
                let selected_text = dialog
                    .options
                    .get(dialog.selected_index)
                    .cloned()
                    .unwrap_or_else(|| "<none>".to_string());
                egui::ComboBox::from_id_salt(format!(
                    "prepared_genome_choice_{}",
                    dialog.requested_genome_id
                ))
                .selected_text(selected_text)
                .show_ui(ui, |ui| {
                    for (idx, option) in dialog.options.iter().enumerate() {
                        ui.selectable_value(&mut dialog.selected_index, idx, option.as_str());
                    }
                });
                ui.horizontal(|ui| {
                    if ui
                        .button("Use selected genome")
                        .on_hover_text("Continue operation with selected prepared genome")
                        .clicked()
                    {
                        apply_clicked = true;
                    }
                    if ui
                        .button("Cancel")
                        .on_hover_text("Cancel pending anchored operation")
                        .clicked()
                    {
                        cancel_clicked = true;
                    }
                });
            });
        }

        if !open || cancel_clicked {
            self.anchor_prepared_choice_dialog = None;
            if cancel_clicked {
                self.op_status = "Cancelled genome-anchor operation".to_string();
            }
            return;
        }

        if apply_clicked {
            let Some(dialog) = self.anchor_prepared_choice_dialog.clone() else {
                return;
            };
            let selected = dialog
                .options
                .get(dialog.selected_index)
                .cloned()
                .or_else(|| dialog.options.first().cloned());
            self.anchor_prepared_choice_dialog = None;
            if let Some(prepared_genome_id) = selected {
                self.run_pending_genome_anchor_action(dialog.action, Some(prepared_genome_id));
            } else {
                self.op_status = "No prepared genome option selected".to_string();
            }
        }
    }

    fn current_pool_members(&self) -> Vec<crate::pool_gel::GelSampleMember> {
        let Some(engine) = &self.engine else {
            return vec![];
        };
        let state = engine.read().expect("Engine lock poisoned");
        self.last_created_seq_ids
            .iter()
            .filter_map(|id| {
                state
                    .state()
                    .sequences
                    .get(id)
                    .map(|dna| crate::pool_gel::GelSampleMember {
                        seq_id: id.clone(),
                        bp: dna.len(),
                        topology_form:
                            crate::engine::GentleEngine::infer_gel_topology_form_from_dna(dna),
                    })
            })
            .collect()
    }

    fn render_pool_distribution(&self, ui: &mut egui::Ui) {
        let mut lengths: Vec<usize> = self
            .current_pool_members()
            .into_iter()
            .map(|member| member.bp)
            .collect();
        if lengths.is_empty() {
            return;
        }
        lengths.sort_unstable();
        let min_bp = *lengths.first().unwrap_or(&0);
        let max_bp = *lengths.last().unwrap_or(&0);
        let median_bp = lengths[lengths.len() / 2];
        ui.monospace(format!(
            "Pool distribution: n={} min={}bp median={}bp max={}bp",
            lengths.len(),
            min_bp,
            median_bp,
            max_bp
        ));

        let span = max_bp.saturating_sub(min_bp);
        let bucket_size = if span <= 500 {
            50
        } else if span <= 2_000 {
            100
        } else {
            250
        };

        let mut buckets: HashMap<usize, usize> = HashMap::new();
        for bp in lengths {
            let idx = (bp - min_bp) / bucket_size;
            *buckets.entry(idx).or_insert(0) += 1;
        }
        let mut bucket_keys: Vec<usize> = buckets.keys().cloned().collect();
        bucket_keys.sort_unstable();
        for idx in bucket_keys {
            let count = buckets.get(&idx).cloned().unwrap_or(0);
            let lo = min_bp + idx * bucket_size;
            let hi = lo + bucket_size.saturating_sub(1);
            let bar = "#".repeat(count.min(40));
            ui.monospace(format!("{:>6}-{:>6} bp | {:>3} {}", lo, hi, count, bar));
        }
    }

    fn render_pool_gel_preview(&self, ui: &mut egui::Ui) {
        let members = self.current_pool_members();
        if members.is_empty() {
            return;
        }
        let ladders = Self::parse_ids(&self.pool_gel_ladders);
        let layout = match build_pool_gel_layout(&members, &ladders, None) {
            Ok(layout) => layout,
            Err(e) => {
                ui.colored_label(egui::Color32::from_rgb(180, 40, 40), e);
                return;
            }
        };
        let ladder_text = if layout.selected_ladders.is_empty() {
            "auto".to_string()
        } else {
            layout.selected_ladders.join(" + ")
        };
        ui.monospace(format!(
            "Pool gel: ladders={} | range={}..{} bp | {}",
            ladder_text,
            layout.range_min_bp,
            layout.range_max_bp,
            layout.conditions.describe()
        ));
        let desired_h = 320.0;
        let desired_w = ui.available_width().max(460.0);
        let (rect, _response) =
            ui.allocate_exact_size(Vec2::new(desired_w, desired_h), egui::Sense::hover());
        let painter = ui.painter_at(rect);

        painter.rect_filled(rect, 8.0, egui::Color32::from_rgb(246, 248, 251));
        let gel_rect = egui::Rect::from_min_max(
            rect.min + Vec2::new(14.0, 18.0),
            rect.max - Vec2::new(180.0, 32.0),
        );
        painter.rect_filled(gel_rect, 8.0, egui::Color32::from_rgb(18, 20, 24));

        let lane_count = layout.lanes.len().max(1);
        let lane_gap = gel_rect.width() / (lane_count as f32 + 1.0);
        let mut ticks = BTreeSet::new();
        for lane in layout.lanes.iter().filter(|l| l.is_ladder) {
            for band in &lane.bands {
                ticks.insert(band.bp);
            }
        }
        if ticks.is_empty() {
            ticks.insert(layout.range_min_bp);
            ticks.insert(layout.range_max_bp);
        }
        let mut accepted_ticks: Vec<usize> = vec![];
        let mut last_y: Option<f32> = None;
        for bp in ticks.iter().rev() {
            let y = layout.y_for_bp(*bp, gel_rect.top(), gel_rect.bottom());
            if last_y.map(|v| (v - y).abs() >= 14.0).unwrap_or(true) {
                accepted_ticks.push(*bp);
                last_y = Some(y);
            }
            if accepted_ticks.len() >= 16 {
                break;
            }
        }
        for bp in accepted_ticks {
            let y = layout.y_for_bp(bp, gel_rect.top(), gel_rect.bottom());
            painter.line_segment(
                [
                    egui::pos2(gel_rect.left(), y),
                    egui::pos2(gel_rect.right(), y),
                ],
                egui::Stroke::new(1.0_f32, egui::Color32::from_rgb(42, 46, 53)),
            );
            painter.text(
                egui::pos2(gel_rect.right() + 8.0, y),
                egui::Align2::LEFT_CENTER,
                format!("{bp} bp"),
                egui::FontId::monospace(10.0),
                egui::Color32::from_rgb(60, 72, 90),
            );
        }

        for (lane_idx, lane) in layout.lanes.iter().enumerate() {
            let x = gel_rect.left() + lane_gap * (lane_idx as f32 + 1.0);
            let lane_rect = egui::Rect::from_center_size(
                egui::pos2(x, gel_rect.center().y),
                Vec2::new(72.0, gel_rect.height() - 8.0),
            );
            painter.rect_filled(
                lane_rect,
                6.0,
                if lane.is_ladder {
                    egui::Color32::from_rgb(27, 33, 42)
                } else {
                    egui::Color32::from_rgb(30, 38, 50)
                },
            );
            for band in &lane.bands {
                let y = layout.y_for_bp(
                    band.apparent_bp,
                    gel_rect.top() + 4.0,
                    gel_rect.bottom() - 4.0,
                );
                let width = if lane.is_ladder {
                    30.0 + 18.0 * band.intensity
                } else {
                    36.0 + 26.0 * band.intensity
                };
                let band_rect = egui::Rect::from_center_size(
                    egui::pos2(x, y),
                    Vec2::new(width, if lane.is_ladder { 3.5 } else { 4.5 }),
                );
                painter.rect_filled(
                    band_rect,
                    2.0,
                    if lane.is_ladder {
                        egui::Color32::from_rgb(232, 236, 242)
                    } else {
                        egui::Color32::from_rgb(245, 158, 11)
                    },
                );
                if !lane.is_ladder {
                    let mut label = if band.min_bp == band.bp {
                        format!("{} bp", band.bp)
                    } else {
                        format!("{}..{} bp", band.min_bp, band.bp)
                    };
                    if band.apparent_bp != band.bp {
                        label.push_str(&format!(" -> {} bp", band.apparent_bp));
                    }
                    if band.count > 1 {
                        label.push_str(&format!(" | merged x{}", band.count));
                    }
                    painter.text(
                        egui::pos2(gel_rect.right() + 72.0, y),
                        egui::Align2::LEFT_CENTER,
                        label,
                        egui::FontId::monospace(10.0),
                        egui::Color32::from_rgb(17, 24, 39),
                    );
                }
            }
            painter.text(
                egui::pos2(x, gel_rect.bottom() + 14.0),
                egui::Align2::CENTER_TOP,
                lane.name.clone(),
                egui::FontId::monospace(10.5),
                egui::Color32::from_rgb(15, 23, 42),
            );
        }
    }

    pub fn render_sequence(&mut self, ui: &mut egui::Ui) {
        crate::gentle_gui_profile_scope!("MainAreaDna::render_sequence");
        let sequence_length_bp = self.dna.read().map(|dna| dna.len()).unwrap_or(0);
        let max_text_length_bp = self
            .dna_display
            .read()
            .map(|display| display.sequence_panel_max_text_length_bp())
            .unwrap_or(200_000);
        if max_text_length_bp > 0 && sequence_length_bp > max_text_length_bp {
            ui.horizontal(|ui| {
                ui.add_space(8.0);
                ui.colored_label(
                    egui::Color32::from_rgb(120, 53, 15),
                    format!(
                        "Sequence text panel hidden: sequence length {} bp exceeds configured limit {} bp (set 0 for unlimited in Configuration -> Graphics).",
                        sequence_length_bp, max_text_length_bp
                    ),
                );
            });
            return;
        }
        ui.add_space(6.0);
        egui::Frame::NONE
            .inner_margin(egui::Margin::symmetric(8, 0))
            .show(ui, |ui| {
                self.map_sequence.render(ui);
            });
    }

